import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.util.Scanner;

public class SecurePathTraversal {

    private static final String BASE_PATH = "/path/to/secure/directory/";

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter the file name: ");
        String fileName = scanner.nextLine();

        try {
            File requestedFile = new File(BASE_PATH + fileName);
            if (requestedFile.getCanonicalPath().startsWith(BASE_PATH)) {
                BufferedReader br = new BufferedReader(new FileReader(requestedFile));
                String line;

                while ((line = br.readLine()) != null) {
                    System.out.println(line);
                }

                br.close();
            } else {
                System.out.println("Access to this file is not allowed.");
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

